import styled from "styled-components";

const StyledNavbar = styled.div`
  background-color: #b8a96e;
  height: 5vh;
  display: flex;
  justify-content: flex-end;
  vertical-align: bottom;
`;

const StyledA = styled.a`
  color: black;
  underline: none;
  text-decoration: !underline;
  margin: 10px 20px 0px 10px;
`;
const Navbar = () => {
  return (
    <StyledNavbar>
      <StyledA>About me</StyledA>
      <StyledA>Resume</StyledA>
      <StyledA>Professional Accomplishments</StyledA>
      <StyledA>Personal Projects</StyledA>
      <StyledA>Contact</StyledA>
    </StyledNavbar>
  );
};

export default Navbar;
